$_MODULE['<{retractationcommande}prestashop>modal_c41af0bc59217001d2912ae37146555b'] = 'Confirmar el desistimiento';
$_MODULE['<{retractationcommande}prestashop>modal_f64e4c1e50abe85bbda9fd9abadcaa91'] = 'Al confirmar, su solicitud de desistimiento se transmite a nuestro servicio de atención al cliente y se le envía un acuse de recibo por correo electrónico con un ejemplar en PDF (art. L221-21 del Código de Consumo francés). Tras verificar la elegibilidad (plazo legal, exclusiones del art. L221-28), se le comunicará el procedimiento de devolución; le rogamos no enviar los productos antes de recibirlo. El reembolso se efectúa a más tardar 14 días después de la recuperación del bien o de la recepción de la prueba de envío (gastos de envío incluidos en caso de desistimiento total, a prorrata en caso contrario). Los gastos de devolución corren a su cargo.';
$_MODULE['<{retractationcommande}prestashop>modal_c3dfdd738e28bfabd19dd69e3b860058'] = 'Al confirmar, su solicitud de desistimiento se transmite a nuestro servicio de atención al cliente y se le envía un acuse de recibo por correo electrónico con un ejemplar en PDF (art. L221-21 del Código de Consumo francés). Dado que su pedido ya ha sido enviado, puede rechazar el paquete en el momento de la entrega; si lo recibe, no lo abra y siga el procedimiento de devolución que le enviará nuestro servicio de atención al cliente. El reembolso se efectúa a más tardar 14 días después de la recuperación del bien o de la recepción de la prueba de su devolución. Los gastos de devolución corren a su cargo.';
$_MODULE['<{retractationcommande}prestashop>modal_a50e61a0c90d69685028d751c58e4b92'] = 'Al confirmar, su solicitud de desistimiento se transmite a nuestro servicio de atención al cliente y se le envía un acuse de recibo por correo electrónico con un ejemplar en PDF (art. L221-21 del Código de Consumo francés). Dado que su pedido aún no ha sido enviado, no será necesaria ninguna devolución de producto: tras la verificación (exclusiones del art. L221-28), se anulará el envío y se le reembolsará la totalidad de las cantidades abonadas a más tardar 14 días después de su solicitud, mediante el mismo medio de pago.';
$_MODULE['<{retractationcommande}prestashop>formulaire_c690c88abeab5fe0fa53c961a8c22564'] = 'Ejercer mi derecho de desistimiento';
$_MODULE['<{retractationcommande}prestashop>formulaire_d80f966c0798503a14b4ca0d0cc6f7fa'] = 'De conformidad con los artículos L221-18 y siguientes del Código de Consumo francés, dispone de un plazo de';
$_MODULE['<{retractationcommande}prestashop>formulaire_5f1fe455db6e9cab75f31be47d4a301f'] = 'días';
$_MODULE['<{retractationcommande}prestashop>formulaire_9fed21f0eb9a54cd11584bdc72817da7'] = 'a partir del día siguiente a la entrega para desistir, sin necesidad de motivar su decisión. Si este plazo finaliza en sábado, domingo o día festivo, se prorroga hasta el primer día hábil siguiente.';
