$_MODULE['<{retractationcommande}prestashop>formulaire_1e8ba54ca05a4d16b3314cd53c6d7847'] = 'Derecho de desistimiento ejercitable';
$_MODULE['<{retractationcommande}prestashop>formulaire_e1b2374a2b9670a77ca0c7ae9199ad3a'] = 'Este pedido no es (o ya no es) elegible para el desistimiento en línea: plazo legal vencido, solicitud ya presentada o pedido no afectado. Para cualquier pregunta, póngase en contacto con nuestro servicio de atención al cliente.';
$_MODULE['<{retractationcommande}prestashop>formulaire_8fdb7ef7cb418c21ac083c86b78ce700'] = 'El derecho de desistimiento no se aplica a determinados contratos (art. L221-28 del Código de Consumo: bienes a medida o personalizados, bienes perecederos, bienes desprecintados por razones de higiene, etc.). Una vez presentada, su solicitud es verificada por nuestro servicio de atención al cliente, que le envía el procedimiento de devolución. El reembolso se efectúa a más tardar 14 días después de la recuperación del bien o de la recepción de la prueba de envío, mediante el mismo medio de pago. Los gastos de devolución corren a su cargo.';
$_MODULE['<{retractationcommande}prestashop>formulaire_40333b8af27e3198afa43c960e43a3b8'] = 'Derecho de desistimiento';
