$_MODULE['<{retractationcommande}prestashop>demande_ae6c41ce3d6f31f73f9d143bcae0f6b2'] = 'Este pedido ya no es elegible para el desistimiento (plazo legal vencido o productos ya en proceso de desistimiento).';
$_MODULE['<{retractationcommande}prestashop>demande_3a6a3681876ab1e4c55fdecb70fab698'] = 'El mensaje contiene caracteres no permitidos.';
$_MODULE['<{retractationcommande}prestashop>demande_0f9a15225078e2688ee78b984640f46d'] = 'Cantidad solicitada superior a la cantidad susceptible de desistimiento.';
$_MODULE['<{retractationcommande}prestashop>demande_36c075970e7709b21dc06b19cb75c19e'] = 'Seleccione al menos un producto para desistir.';
$_MODULE['<{retractationcommande}prestashop>demande_b0998d501f75050aa4045d17399c25d0'] = 'No se ha podido registrar la solicitud. Póngase en contacto con el servicio de atención al cliente.';
$_MODULE['<{retractationcommande}prestashop>demande_9914a2c75cdd71876e656e7621e47300'] = 'Su desistimiento se ha registrado correctamente con la referencia %s. Se le ha enviado un acuse de recibo por correo electrónico. Nuestro servicio de atención al cliente verificará su solicitud y le enviará el procedimiento de devolución.';
$_MODULE['<{retractationcommande}prestashop>demande_049d1d68c945230da39359dbd32e1d48'] = 'Su desistimiento se ha registrado con la referencia %s. Se le ha enviado un acuse de recibo por correo electrónico. Dado que su pedido ya ha sido enviado, puede rechazar el paquete en el momento de la entrega o, si lo recibe, seguir el procedimiento de devolución que le enviará nuestro servicio de atención al cliente.';
$_MODULE['<{retractationcommande}prestashop>demande_f49c93cbb2dab9d8c4b41d7e8a0f346d'] = 'Su desistimiento se ha registrado correctamente con la referencia %s. Se le ha enviado un acuse de recibo por correo electrónico. Dado que su pedido aún no ha sido enviado, no será necesaria ninguna devolución de producto: tras la verificación, se anulará el envío y se le reembolsará.';
$_MODULE['<{retractationcommande}prestashop>demande_5a06e6b127a7d1baaf18d35bde389969'] = 'Nuestro servicio de atención al cliente verificará la elegibilidad de su solicitud (plazo legal de 14 días, exclusiones del artículo L221-28). Si es conforme, se le enviará el procedimiento de devolución por correo electrónico y, a continuación, el reembolso se efectuará a más tardar 14 días después de la recuperación del bien o de la recepción de la prueba de envío. Le rogamos no enviar el producto antes de recibir el procedimiento de devolución.';
$_MODULE['<{retractationcommande}prestashop>demande_b91f8258aeb37ba358b04427913bd6b1'] = 'A verificar: plazo de 14 días, exclusiones legales (art. L221-28), productos ya devueltos.';
$_MODULE['<{retractationcommande}prestashop>demande_869cbd236cf583ec668d9f90469f561c'] = 'Su pedido ya ha sido enviado y está en tránsito. Puede rechazar el paquete en el momento de la entrega; si lo recibe, no lo abra y espere el procedimiento de devolución que le enviará nuestro servicio de atención al cliente tras la verificación. El reembolso se efectuará a más tardar 14 días después de la recuperación del bien o de la recepción de la prueba de su devolución.';
$_MODULE['<{retractationcommande}prestashop>demande_e32237222087921238a826c436916179'] = 'PEDIDO ENVIADO (en tránsito) — el paquete ha salido: prevea un rechazo del paquete o una devolución. A verificar: exclusiones legales (art. L221-28). El plazo de 14 días solo empezará en la entrega.';
$_MODULE['<{retractationcommande}prestashop>demande_ba6e3c755dec44b85c76f4e9e919450b'] = 'Dado que su pedido aún no ha sido enviado, no será necesaria ninguna devolución de producto. Tras la verificación de su solicitud por nuestro servicio de atención al cliente, se anulará el envío y se le reembolsará la totalidad de las cantidades abonadas a más tardar 14 días después de su solicitud, mediante el mismo medio de pago (art. L221-24).';
$_MODULE['<{retractationcommande}prestashop>demande_ecbc815f858a7d4a0ff0fe67f6eea2a3'] = 'PEDIDO NO ENVIADO — anulación antes del envío: no se espera ninguna devolución de producto. A verificar: exclusiones legales (art. L221-28). No olvide bloquear el envío antes de validar.';
$_MODULE['<{retractationcommande}prestashop>demande_00e9581137cc9fcce29afdb92e74d13a'] = 'Enviado, en tránsito';
